function createCounter() {
  let count = 0;
  return () => ++count;
}

const next = createCounter();
next(); // 1
next(); // 2

function makeGreeter(name) {
  return function greet() {
    return `Hello, ${name}`;
  };
}

const hi = makeGreeter("Ada");
hi(); // Hello, Ada

async function load() {
  try {
    const res = await fetch("/api/user");
    const data = await res.json();
    return data;
  } catch (e) {
    console.error(e);
  }
}
